// Living biomimetic background — drifting bioluminescent motes + slow auroral waves.
// Rendered on #bg-canvas. Respects prefers-reduced-motion.

(function initBackground() {
  const canvas = document.getElementById('bg-canvas');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  const reduce = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

  let W = 0, H = 0, dpr = Math.min(window.devicePixelRatio || 1, 2);

  function resize() {
    W = window.innerWidth; H = window.innerHeight;
    canvas.width = W * dpr; canvas.height = H * dpr;
    canvas.style.width = W + 'px'; canvas.style.height = H + 'px';
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  }
  resize();
  window.addEventListener('resize', resize);

  // Read current bio color from CSS vars (updates when palette swaps)
  function palette() {
    const cs = getComputedStyle(document.documentElement);
    const el = document.querySelector('[data-palette]') || document.documentElement;
    const css = getComputedStyle(el);
    return {
      bio: (css.getPropertyValue('--bio') || cs.getPropertyValue('--bio')).trim() || '#4fd1c5',
      hi:  (css.getPropertyValue('--bio-hi') || cs.getPropertyValue('--bio-hi')).trim() || '#a0f0e8',
      amber: (css.getPropertyValue('--amber') || cs.getPropertyValue('--amber')).trim() || '#e8c070',
    };
  }

  // Seed motes (drifting spore / plankton)
  const MOTE_COUNT = reduce ? 0 : 80;
  const motes = Array.from({ length: MOTE_COUNT }, () => ({
    x: Math.random() * 1000,
    y: Math.random() * 1000,
    r: 0.3 + Math.random() * 1.6,
    vx: (Math.random() - 0.5) * 0.12,
    vy: -0.02 - Math.random() * 0.08,
    phase: Math.random() * Math.PI * 2,
    speed: 0.4 + Math.random() * 0.8,
    kind: Math.random() < 0.1 ? 'amber' : 'bio',
  }));

  // Aurora bands — slow horizontal sin waves
  const bands = [
    { y: 0.25, amp: 40, freq: 0.003, speed: 0.00012, alpha: 0.06 },
    { y: 0.55, amp: 70, freq: 0.002, speed: 0.00008, alpha: 0.04 },
    { y: 0.82, amp: 55, freq: 0.0025, speed: -0.0001, alpha: 0.05 },
  ];

  // Intensity: 0..1, exposed on window for tweaks
  window.__bgIntensity = 1;

  function draw(t) {
    const I = window.__bgIntensity ?? 1;
    const p = palette();
    ctx.clearRect(0, 0, W, H);

    // Aurora bands
    if (I > 0.05) {
      ctx.save();
      ctx.globalCompositeOperation = 'screen';
      bands.forEach((b, i) => {
        const grad = ctx.createLinearGradient(0, 0, W, 0);
        grad.addColorStop(0,    'rgba(0,0,0,0)');
        grad.addColorStop(0.3,  hexWithAlpha(p.bio, b.alpha * I));
        grad.addColorStop(0.7,  hexWithAlpha(i === 1 ? p.hi : p.bio, b.alpha * 0.8 * I));
        grad.addColorStop(1,    'rgba(0,0,0,0)');
        ctx.fillStyle = grad;
        ctx.beginPath();
        const y0 = H * b.y;
        ctx.moveTo(0, y0);
        for (let x = 0; x <= W; x += 6) {
          const y = y0 + Math.sin(x * b.freq + t * b.speed) * b.amp
                       + Math.sin(x * b.freq * 2.3 + t * b.speed * 1.7) * b.amp * 0.3;
          ctx.lineTo(x, y);
        }
        ctx.lineTo(W, y0 + 120);
        ctx.lineTo(0, y0 + 120);
        ctx.closePath();
        ctx.fill();
      });
      ctx.restore();
    }

    // Motes
    if (I > 0.05) {
      ctx.save();
      ctx.globalCompositeOperation = 'screen';
      for (const m of motes) {
        m.x += m.vx; m.y += m.vy;
        m.phase += 0.01 * m.speed;
        if (m.y < -10) { m.y = H + 10; m.x = Math.random() * W; }
        if (m.x < -10) m.x = W + 10;
        if (m.x > W + 10) m.x = -10;

        const pulse = 0.5 + 0.5 * Math.sin(m.phase);
        const alpha = (0.12 + 0.5 * pulse) * I;
        const color = m.kind === 'amber' ? p.amber : p.hi;
        const r = m.r * (0.8 + 0.4 * pulse);

        // Glow
        const g = ctx.createRadialGradient(m.x, m.y, 0, m.x, m.y, r * 6);
        g.addColorStop(0, hexWithAlpha(color, alpha));
        g.addColorStop(1, hexWithAlpha(color, 0));
        ctx.fillStyle = g;
        ctx.beginPath(); ctx.arc(m.x, m.y, r * 6, 0, Math.PI * 2); ctx.fill();

        // Core
        ctx.fillStyle = hexWithAlpha(color, Math.min(1, alpha * 2.4));
        ctx.beginPath(); ctx.arc(m.x, m.y, r, 0, Math.PI * 2); ctx.fill();
      }
      ctx.restore();
    }

    requestAnimationFrame(draw);
  }

  function hexWithAlpha(hex, a) {
    // Accept #rrggbb or rgb()
    hex = hex.trim();
    if (hex.startsWith('#')) {
      const h = hex.length === 4
        ? '#' + [...hex.slice(1)].map(c => c + c).join('')
        : hex;
      const r = parseInt(h.slice(1, 3), 16);
      const g = parseInt(h.slice(3, 5), 16);
      const b = parseInt(h.slice(5, 7), 16);
      return `rgba(${r},${g},${b},${a})`;
    }
    return hex;
  }

  requestAnimationFrame(draw);
})();

// Life Wheel — breathing radial cockpit. SVG. 8 sectors for LD01..LD08.
// Props: size, variant ('radial'|'hex'), breathing (bool), blurred (bool), data (array[8])

const { useState, useEffect, useRef, useMemo } = React;

const LIFEWHEEL_SECTORS = [
  { code: "LD01", glyph: "◐", angle:  90 },
  { code: "LD02", glyph: "◓", angle: 135 },
  { code: "LD03", glyph: "◑", angle: 180 },
  { code: "LD04", glyph: "◒", angle: 225 },
  { code: "LD05", glyph: "◐", angle: 270 },
  { code: "LD06", glyph: "◓", angle: 315 },
  { code: "LD07", glyph: "◑", angle:   0 },
  { code: "LD08", glyph: "◒", angle:  45 },
];

function polar(cx, cy, r, deg) {
  const a = (deg - 90) * Math.PI / 180;
  return [cx + r * Math.cos(a), cy + r * Math.sin(a)];
}

function LifeWheel({ size = 560, breathing = true, blurred = false, data, showReadouts = true, intensity = 1 }) {
  const vals = useMemo(() => data || LIFEWHEEL_SECTORS.map((_, i) => 0.35 + ((i * 13 + 7) % 10) / 15), [data]);
  const [t, setT] = useState(0);

  useEffect(() => {
    if (!breathing) return;
    let raf;
    const start = performance.now();
    const loop = (now) => {
      setT((now - start) / 1000);
      raf = requestAnimationFrame(loop);
    };
    raf = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(raf);
  }, [breathing]);

  const cx = size / 2, cy = size / 2;
  const rOuter = size * 0.44;
  const rGrid1 = size * 0.36;
  const rGrid2 = size * 0.28;
  const rGrid3 = size * 0.20;
  const rCore  = size * 0.08;

  // Breathing modulation
  const breath = 1 + Math.sin(t * 0.8) * 0.015 * intensity;
  const pulse  = 0.5 + 0.5 * Math.sin(t * 1.2);

  return (
    <div
      style={{
        position: "relative",
        width: size, height: size,
        filter: blurred ? "blur(6px) saturate(0.8)" : "none",
        transition: "filter 0.6s ease",
      }}
    >
      <svg
        width={size} height={size} viewBox={`0 0 ${size} ${size}`}
        style={{ display: "block", transform: `scale(${breath})`, transition: "transform 0.1s linear" }}
      >
        <defs>
          <radialGradient id="lw-core" cx="50%" cy="50%" r="50%">
            <stop offset="0%" stopColor="var(--bio-hi)" stopOpacity="0.8"/>
            <stop offset="40%" stopColor="var(--bio)" stopOpacity="0.4"/>
            <stop offset="100%" stopColor="var(--bio)" stopOpacity="0"/>
          </radialGradient>
          <radialGradient id="lw-ring" cx="50%" cy="50%" r="50%">
            <stop offset="70%" stopColor="var(--bio)" stopOpacity="0"/>
            <stop offset="100%" stopColor="var(--bio)" stopOpacity="0.08"/>
          </radialGradient>
          <filter id="lw-glow" x="-30%" y="-30%" width="160%" height="160%">
            <feGaussianBlur stdDeviation="2" />
            <feComposite in2="SourceGraphic" operator="over" />
          </filter>
        </defs>

        {/* Outer atmospheric ring */}
        <circle cx={cx} cy={cy} r={rOuter + 14} fill="url(#lw-ring)" />

        {/* Grid rings */}
        {[rOuter, rGrid1, rGrid2, rGrid3].map((r, i) => (
          <circle key={i} cx={cx} cy={cy} r={r}
            fill="none"
            stroke="var(--bio)"
            strokeOpacity={i === 0 ? 0.35 : 0.12}
            strokeWidth={i === 0 ? 0.6 : 0.4}
            strokeDasharray={i === 0 ? "none" : "2 3"}
          />
        ))}

        {/* Radial spokes */}
        {LIFEWHEEL_SECTORS.map((s, i) => {
          const [x, y] = polar(cx, cy, rOuter, s.angle);
          return (
            <line key={i} x1={cx} y1={cy} x2={x} y2={y}
              stroke="var(--bio)" strokeOpacity="0.15" strokeWidth="0.5" />
          );
        })}

        {/* Sector value arcs — like a polar bar chart */}
        {LIFEWHEEL_SECTORS.map((s, i) => {
          const v = vals[i];
          const r = rGrid3 + (rOuter - rGrid3) * v;
          const startAngle = s.angle - 20;
          const endAngle = s.angle + 20;
          const [x1, y1] = polar(cx, cy, r, startAngle);
          const [x2, y2] = polar(cx, cy, r, endAngle);
          const [xi1, yi1] = polar(cx, cy, rGrid3 + 4, startAngle);
          const [xi2, yi2] = polar(cx, cy, rGrid3 + 4, endAngle);
          const sectorPulse = 0.5 + 0.5 * Math.sin(t * 0.6 + i * 0.7);
          return (
            <g key={s.code}>
              <path
                d={`M ${xi1} ${yi1} A ${rGrid3 + 4} ${rGrid3 + 4} 0 0 1 ${xi2} ${yi2} L ${x2} ${y2} A ${r} ${r} 0 0 0 ${x1} ${y1} Z`}
                fill="var(--bio)"
                fillOpacity={0.08 + 0.06 * sectorPulse}
                stroke="var(--bio)"
                strokeOpacity={0.35 + 0.2 * sectorPulse}
                strokeWidth="0.6"
              />
              {/* Sector tick marker */}
              <circle cx={(x1+x2)/2 + (polar(cx,cy,r+6,s.angle)[0]-((x1+x2)/2))*0} cy={(y1+y2)/2}
                r="0" fill="var(--bio-hi)" />
            </g>
          );
        })}

        {/* Sector labels around perimeter */}
        {LIFEWHEEL_SECTORS.map((s, i) => {
          const [lx, ly] = polar(cx, cy, rOuter + 22, s.angle);
          const [dx, dy] = polar(cx, cy, rOuter + 2, s.angle);
          return (
            <g key={`lbl-${i}`}>
              <line x1={dx} y1={dy}
                x2={polar(cx, cy, rOuter + 10, s.angle)[0]}
                y2={polar(cx, cy, rOuter + 10, s.angle)[1]}
                stroke="var(--bio)" strokeOpacity="0.6" strokeWidth="0.6" />
              <text
                x={lx} y={ly}
                fill="var(--fg-dim)"
                fontFamily="var(--mono)" fontSize="9" letterSpacing="1.4"
                textAnchor="middle" dominantBaseline="middle"
              >{s.code}</text>
            </g>
          );
        })}

        {/* Rotating reticle */}
        <g style={{ transform: `rotate(${t * 8}deg)`, transformOrigin: `${cx}px ${cy}px` }}>
          {[0, 90, 180, 270].map(a => {
            const [x, y] = polar(cx, cy, rOuter + 6, a);
            return <circle key={a} cx={x} cy={y} r="1.4" fill="var(--bio-hi)" opacity="0.85" />;
          })}
        </g>

        {/* Counter-rotating inner tick ring */}
        <g style={{ transform: `rotate(${-t * 4}deg)`, transformOrigin: `${cx}px ${cy}px` }}>
          {Array.from({ length: 48 }).map((_, i) => {
            const a = i * (360 / 48);
            const [x1, y1] = polar(cx, cy, rGrid2 - 3, a);
            const [x2, y2] = polar(cx, cy, rGrid2, a);
            return <line key={i} x1={x1} y1={y1} x2={x2} y2={y2}
              stroke="var(--bio)" strokeOpacity={i % 4 === 0 ? 0.5 : 0.18} strokeWidth="0.5" />;
          })}
        </g>

        {/* Core — the Ikigai pulse */}
        <circle cx={cx} cy={cy} r={rCore * (1 + pulse * 0.15)} fill="url(#lw-core)" />
        <circle cx={cx} cy={cy} r={rCore * 0.5} fill="var(--bio-hi)" opacity={0.6 + pulse * 0.4} />
        <circle cx={cx} cy={cy} r={1.6} fill="#fff" />

        {/* Crosshair */}
        <g stroke="var(--bio)" strokeOpacity="0.3" strokeWidth="0.5">
          <line x1={cx - rCore - 6} y1={cy} x2={cx - rCore - 2} y2={cy} />
          <line x1={cx + rCore + 2} y1={cy} x2={cx + rCore + 6} y2={cy} />
          <line x1={cx} y1={cy - rCore - 6} x2={cx} y2={cy - rCore - 2} />
          <line x1={cx} y1={cy + rCore + 2} x2={cx} y2={cy + rCore + 6} />
        </g>

        {/* Inner text — Ikigai label */}
        <text x={cx} y={cy - rCore - 16} fill="var(--bio-hi)" fontFamily="var(--mono)" fontSize="8" letterSpacing="2" textAnchor="middle" opacity="0.9">IKIGAI · CORE</text>
      </svg>

      {/* Corner readouts — cockpit instruments */}
      {showReadouts && !blurred && (
        <>
          <Readout pos={{ top: 0, left: 0 }} label="COHERENCE" value={(0.72 + Math.sin(t * 0.5) * 0.04).toFixed(3)} />
          <Readout pos={{ top: 0, right: 0 }} label="ALIGNMENT" value={`${(86 + Math.sin(t * 0.7) * 2).toFixed(1)}%`} align="right" />
          <Readout pos={{ bottom: 0, left: 0 }} label="CADENCE" value="12WY · W03" />
          <Readout pos={{ bottom: 0, right: 0 }} label="HARMONIC" value={`${(432 + Math.sin(t) * 0.6).toFixed(2)} Hz`} align="right" />
        </>
      )}
    </div>
  );
}

function Readout({ pos, label, value, align = "left" }) {
  return (
    <div style={{
      position: "absolute", ...pos,
      fontFamily: "var(--mono)", fontSize: 9, letterSpacing: 1.4,
      color: "var(--fg-dim)", textAlign: align, lineHeight: 1.4,
      pointerEvents: "none",
    }}>
      <div style={{ opacity: 0.6, textTransform: "uppercase" }}>{label}</div>
      <div style={{ color: "var(--bio-hi)", fontSize: 11, marginTop: 2, fontVariantNumeric: "tabular-nums" }}>{value}</div>
    </div>
  );
}

window.LifeWheel = LifeWheel;
window.LIFEWHEEL_SECTORS = LIFEWHEEL_SECTORS;

// 8 Hubs grid — LD01..LD08. Solarpunk cards with organic line icons.

const HUBS = [
  { code: "LD01", name: "Le Foyer",       en: "The Hearth",       tag: "Ground · Home · Body",           glyph: "hearth",  desc: "Le feu domestique. Where the day begins and returns." },
  { code: "LD02", name: "L'Atelier",      en: "The Atelier",      tag: "Craft · Making · Mastery",       glyph: "atelier", desc: "Tools on the bench. The hand that shapes matter into meaning." },
  { code: "LD03", name: "La Canopée",     en: "The Canopy",       tag: "Mind · Reading · Study",         glyph: "canopy",  desc: "Light through leaves. Ideas sorted into soil and sun." },
  { code: "LD04", name: "Le Rhizome",     en: "The Rhizome",      tag: "Relations · Kinship · Network",  glyph: "rhizome", desc: "Underground threads. Everyone you've ever chosen." },
  { code: "LD05", name: "Les Réserves",   en: "The Stores",       tag: "Wealth · Resources · Flow",      glyph: "stores",  desc: "What you hold so you can give. Currency, attention, time." },
  { code: "LD06", name: "La Boussole",    en: "The Compass",      tag: "Purpose · Ikigai · Why",         glyph: "compass", desc: "The single needle that orients every other instrument." },
  { code: "LD07", name: "Le Sanctuaire",  en: "The Sanctuary",    tag: "Spirit · Stillness · Rite",      glyph: "sanctuary", desc: "Silence with a roof. Where you meet the part of yourself that does not speak." },
  { code: "LD08", name: "L'Horizon",      en: "The Horizon",      tag: "Vision · Legacy · 12WY",         glyph: "horizon", desc: "Twelve weeks, twelve years. The long line drawn forward." },
];

function HubGlyph({ kind, size = 56 }) {
  const s = size;
  const cx = s / 2, cy = s / 2;
  const stroke = { stroke: "currentColor", strokeWidth: 0.8, fill: "none", strokeLinecap: "round" };
  const glyphs = {
    hearth: (
      <g {...stroke}>
        <path d={`M ${cx-14} ${cy+10} L ${cx-14} ${cy-4} L ${cx} ${cy-16} L ${cx+14} ${cy-4} L ${cx+14} ${cy+10} Z`} />
        <path d={`M ${cx-4} ${cy+10} L ${cx-4} ${cy+2} Q ${cx} ${cy-2} ${cx+4} ${cy+2} L ${cx+4} ${cy+10}`} />
        <path d={`M ${cx} ${cy-6} Q ${cx+3} ${cy-3} ${cx} ${cy} Q ${cx-3} ${cy-3} ${cx} ${cy-6}`} opacity="0.7"/>
      </g>
    ),
    atelier: (
      <g {...stroke}>
        <circle cx={cx} cy={cy} r="14"/>
        <path d={`M ${cx-10} ${cy} L ${cx+10} ${cy}`}/>
        <path d={`M ${cx} ${cy-10} L ${cx} ${cy+10}`}/>
        <circle cx={cx} cy={cy} r="3" fill="currentColor" opacity="0.6"/>
        <path d={`M ${cx-14} ${cy-8} L ${cx-8} ${cy-14}`}/>
        <path d={`M ${cx+14} ${cy+8} L ${cx+8} ${cy+14}`}/>
      </g>
    ),
    canopy: (
      <g {...stroke}>
        <path d={`M ${cx} ${cy+14} L ${cx} ${cy-14}`}/>
        <path d={`M ${cx} ${cy-2} Q ${cx-10} ${cy-8} ${cx-14} ${cy-14}`}/>
        <path d={`M ${cx} ${cy-2} Q ${cx+10} ${cy-8} ${cx+14} ${cy-14}`}/>
        <path d={`M ${cx} ${cy+4} Q ${cx-8} ${cy-2} ${cx-12} ${cy-6}`}/>
        <path d={`M ${cx} ${cy+4} Q ${cx+8} ${cy-2} ${cx+12} ${cy-6}`}/>
        <circle cx={cx} cy={cy-12} r="1.2" fill="currentColor"/>
      </g>
    ),
    rhizome: (
      <g {...stroke}>
        <circle cx={cx-10} cy={cy-8} r="2.5"/>
        <circle cx={cx+10} cy={cy-8} r="2.5"/>
        <circle cx={cx} cy={cy+2} r="2.5"/>
        <circle cx={cx-8} cy={cy+12} r="2.5"/>
        <circle cx={cx+8} cy={cy+12} r="2.5"/>
        <path d={`M ${cx-10} ${cy-8} Q ${cx-4} ${cy-2} ${cx} ${cy+2}`}/>
        <path d={`M ${cx+10} ${cy-8} Q ${cx+4} ${cy-2} ${cx} ${cy+2}`}/>
        <path d={`M ${cx} ${cy+2} Q ${cx-4} ${cy+8} ${cx-8} ${cy+12}`}/>
        <path d={`M ${cx} ${cy+2} Q ${cx+4} ${cy+8} ${cx+8} ${cy+12}`}/>
        <path d={`M ${cx-10} ${cy-8} Q ${cx} ${cy-14} ${cx+10} ${cy-8}`} opacity="0.4"/>
      </g>
    ),
    stores: (
      <g {...stroke}>
        <ellipse cx={cx} cy={cy-8} rx="12" ry="3"/>
        <path d={`M ${cx-12} ${cy-8} L ${cx-12} ${cy+8} Q ${cx} ${cy+12} ${cx+12} ${cy+8} L ${cx+12} ${cy-8}`}/>
        <path d={`M ${cx-12} ${cy-2} Q ${cx} ${cy+2} ${cx+12} ${cy-2}`} opacity="0.6"/>
        <path d={`M ${cx-12} ${cy+4} Q ${cx} ${cy+8} ${cx+12} ${cy+4}`} opacity="0.4"/>
      </g>
    ),
    compass: (
      <g {...stroke}>
        <circle cx={cx} cy={cy} r="14"/>
        <path d={`M ${cx} ${cy-12} L ${cx+3} ${cy} L ${cx} ${cy+12} L ${cx-3} ${cy} Z`} fill="currentColor" fillOpacity="0.3"/>
        <circle cx={cx} cy={cy} r="1.4" fill="currentColor"/>
        <path d={`M ${cx} ${cy-16} L ${cx} ${cy-14}`}/>
        <path d={`M ${cx} ${cy+14} L ${cx} ${cy+16}`}/>
        <path d={`M ${cx-16} ${cy} L ${cx-14} ${cy}`}/>
        <path d={`M ${cx+14} ${cy} L ${cx+16} ${cy}`}/>
      </g>
    ),
    sanctuary: (
      <g {...stroke}>
        <path d={`M ${cx-12} ${cy+12} L ${cx-12} ${cy-2} Q ${cx} ${cy-14} ${cx+12} ${cy-2} L ${cx+12} ${cy+12} Z`}/>
        <path d={`M ${cx-6} ${cy+12} L ${cx-6} ${cy+2} Q ${cx} ${cy-2} ${cx+6} ${cy+2} L ${cx+6} ${cy+12}`}/>
        <circle cx={cx} cy={cy-6} r="1.2" fill="currentColor"/>
      </g>
    ),
    horizon: (
      <g {...stroke}>
        <path d={`M ${cx-14} ${cy+4} L ${cx+14} ${cy+4}`}/>
        <circle cx={cx+4} cy={cy-2} r="6"/>
        <path d={`M ${cx-14} ${cy+8} L ${cx+14} ${cy+8}`} opacity="0.5"/>
        <path d={`M ${cx-14} ${cy+12} L ${cx+14} ${cy+12}`} opacity="0.25"/>
      </g>
    ),
  };
  return (
    <svg width={s} height={s} viewBox={`0 0 ${s} ${s}`} style={{ color: "var(--bio)" }}>
      {glyphs[kind]}
    </svg>
  );
}

function HubsGrid() {
  const [hover, setHover] = useState(null);
  return (
    <div style={{
      display: "grid",
      gridTemplateColumns: "repeat(4, 1fr)",
      gap: "1px",
      background: "var(--ink-line)",
      border: "1px solid var(--ink-line)",
    }}>
      {HUBS.map((h, i) => (
        <article
          key={h.code}
          onMouseEnter={() => setHover(i)}
          onMouseLeave={() => setHover(null)}
          style={{
            background: hover === i ? "var(--ink-soft)" : "var(--ink-deep)",
            padding: "28px 24px 24px",
            minHeight: 240,
            position: "relative",
            transition: "background 0.3s ease",
            cursor: "crosshair",
            overflow: "hidden",
          }}
        >
          {/* Corner brackets */}
          <Corners active={hover === i} />

          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 28 }}>
            <span className="mono-xs" style={{ color: "var(--bio)", opacity: 0.8 }}>{h.code}</span>
            <span className="mono-xs" style={{ color: "var(--fg-faint)" }}>HUB {String(i+1).padStart(2,"0")}/08</span>
          </div>

