function Diagram({ kind, width = 220, height = 140 }) {
  const stroke = { stroke: "var(--bio)", fill: "none", strokeWidth: 0.8, strokeLinecap: "round" };
  const faint  = { stroke: "var(--bio)", fill: "none", strokeWidth: 0.5, strokeLinecap: "round", opacity: 0.35 };
  const label = (x, y, t) => (
    <text x={x} y={y} fill="var(--fg-faint)" fontFamily="var(--mono)" fontSize="7" letterSpacing="1">{t}</text>
  );

  if (kind === "twelvewy") {
    // 12 weekly bars, grouped into 4 sprints of 3
    return (
      <svg width={width} height={height} viewBox="0 0 220 140">
        {label(10, 16, "ORBIT · 12W")}
        {[0,1,2,3].map(sprint => (
          <g key={sprint}>
            {[0,1,2].map(w => {
              const i = sprint * 3 + w;
              const x = 14 + i * 16;
              const h = 30 + (Math.sin(i * 1.3) + 1) * 20;
              return (
                <g key={w}>
                  <rect x={x} y={100 - h} width="10" height={h}
                    fill="var(--bio)" fillOpacity={0.2 + w * 0.15} stroke="var(--bio)" strokeOpacity="0.6" strokeWidth="0.4"/>
                  <text x={x+5} y={112} fill="var(--fg-faint)" fontFamily="var(--mono)" fontSize="6" textAnchor="middle">W{i+1}</text>
                </g>
              );
            })}
            <line x1={14 + sprint*48 - 2} y1={120} x2={14 + sprint*48 + 44} y2={120} {...stroke} strokeWidth="0.4"/>
            <text x={14 + sprint*48 + 21} y={132} fill="var(--bio-ghost)" fontFamily="var(--mono)" fontSize="7" textAnchor="middle">S{sprint+1}</text>
          </g>
        ))}
        <line x1={10} y1={100} x2={210} y2={100} {...faint}/>
      </svg>
    );
  }
  if (kind === "para") {
    // 4 nested frames
    return (
      <svg width={width} height={height} viewBox="0 0 220 140">
        {[
          { x: 20, y: 20, w: 180, h: 100, label: "ARCHIVE", opacity: 0.3 },
          { x: 32, y: 32, w: 156, h: 76, label: "RESOURCES", opacity: 0.5 },
          { x: 46, y: 46, w: 128, h: 48, label: "AREAS", opacity: 0.75 },
          { x: 62, y: 58, w: 96, h: 24, label: "PROJECTS", opacity: 1 },
        ].map((f, i) => (
          <g key={i}>
            <rect x={f.x} y={f.y} width={f.w} height={f.h} fill="none"
              stroke="var(--bio)" strokeOpacity={f.opacity * 0.9} strokeWidth="0.6"/>
            <text x={f.x + 4} y={f.y + 8} fill="var(--bio)" fontFamily="var(--mono)" fontSize="6" letterSpacing="1" opacity={f.opacity}>{f.label}</text>
          </g>
        ))}
        {/* Flow arrow */}
        <path d="M 170 70 L 200 70 L 200 120 L 10 120 L 10 70 L 18 70" {...faint} strokeDasharray="2 2"/>
        <text x={110} y={134} fill="var(--fg-faint)" fontFamily="var(--mono)" fontSize="6" textAnchor="middle" letterSpacing="1">ACTIONABILITY →</text>
      </svg>
    );
  }
  if (kind === "gtd") {
    // Horizontal flow of 5 nodes
    const steps = ["CAPTURE","CLARIFY","ORGANIZE","REFLECT","ENGAGE"];
    return (
      <svg width={width} height={height} viewBox="0 0 220 140">
        {steps.map((s, i) => {
          const x = 14 + i * 48;
          return (
            <g key={i}>
              <circle cx={x} cy={70} r="8" fill="var(--ink-deep)" stroke="var(--bio)" strokeWidth="0.8"/>
              <circle cx={x} cy={70} r="2.5" fill="var(--bio)" opacity={0.3 + i * 0.15}/>
              {i < 4 && <path d={`M ${x+8} 70 L ${x+40} 70`} stroke="var(--bio)" strokeWidth="0.6" strokeOpacity="0.5" markerEnd="url(#arr)"/>}
              <text x={x} y={92} fill="var(--fg-faint)" fontFamily="var(--mono)" fontSize="6" textAnchor="middle" letterSpacing="1">{s}</text>
            </g>
          );
        })}
        <defs>
          <marker id="arr" viewBox="0 0 10 10" refX="8" refY="5" markerWidth="4" markerHeight="4" orient="auto">
            <path d="M 0 0 L 10 5 L 0 10 z" fill="var(--bio)" opacity="0.6"/>
          </marker>
        </defs>
        <text x={110} y={36} fill="var(--bio-ghost)" fontFamily="var(--mono)" fontSize="7" textAnchor="middle" letterSpacing="2">MIND → LEDGER → WORLD</text>
        <line x1={14} y1={110} x2={206} y2={110} stroke="var(--bio)" strokeWidth="0.4" strokeOpacity="0.2"/>
      </svg>
    );
  }
  if (kind === "sob") {
    // Sine wave with markers — ultradian rhythm
    return (
      <svg width={width} height={height} viewBox="0 0 220 140">
        <text x={14} y={20} fill="var(--bio-ghost)" fontFamily="var(--mono)" fontSize="7" letterSpacing="1.5">BIOLOGICAL TIDE</text>
        <path d={(() => {
          let d = "M 10 70 ";
          for (let x = 10; x <= 210; x += 4) {
            const y = 70 + Math.sin((x - 10) * 0.06) * 28;
            d += `L ${x} ${y} `;
          }
          return d;
        })()} stroke="var(--bio)" strokeWidth="1" fill="none" strokeOpacity="0.9"/>
        {/* Secondary harmonic */}
        <path d={(() => {
          let d = "M 10 70 ";
          for (let x = 10; x <= 210; x += 4) {
            const y = 70 + Math.sin((x - 10) * 0.18) * 8;
            d += `L ${x} ${y} `;
          }
          return d;
        })()} stroke="var(--bio)" strokeWidth="0.5" fill="none" strokeOpacity="0.4"/>
        {/* Crests */}
        {[36, 88, 140, 192].map((x, i) => (
          <g key={i}>
            <circle cx={x} cy={70 + Math.sin((x-10)*0.06)*28} r="2.5" fill="var(--bio-hi)"/>
            <line x1={x} y1={70 + Math.sin((x-10)*0.06)*28 + 4} x2={x} y2={120} stroke="var(--bio)" strokeOpacity="0.3" strokeWidth="0.4" strokeDasharray="1 2"/>
            <text x={x} y={132} fill="var(--fg-faint)" fontFamily="var(--mono)" fontSize="6" textAnchor="middle">{["90m","180m","270m","360m"][i]}</text>
          </g>
        ))}
        <line x1={10} y1={70} x2={210} y2={70} stroke="var(--bio)" strokeWidth="0.4" strokeOpacity="0.2" strokeDasharray="2 2"/>
      </svg>
    );
  }
  return null;
}

