// Mobile experience — the Curiosity Filter. Locked vault aesthetic.

function MobileView({ intensity, attitude = "heavy" }) {
  const [email, setEmail] = useState("");
  const [submitted, setSubmitted] = useState(false);
  const [scrambled, setScrambled] = useState("");

  // Scramble tagline effect
  useEffect(() => {
    const target = "DESKTOP CONSOLE ACCESS REQUIRED FOR ORCHESTRATION";
    const chars = "▓▒░█◆◇◈⬢⬡▤▥▦▧▨▩";
    let frame = 0;
    const interval = setInterval(() => {
      if (frame > 30) { setScrambled(target); clearInterval(interval); return; }
      const progress = frame / 30;
      setScrambled(target.split("").map((ch, i) => {
        if (ch === " ") return " ";
        if (i / target.length < progress) return ch;
        return chars[Math.floor(Math.random() * chars.length)];
      }).join(""));
      frame++;
    }, 60);
    return () => clearInterval(interval);
  }, []);

  const onSubmit = (e) => {
    e.preventDefault();
    if (!email.includes("@")) return;
    setSubmitted(true);
  };

  return (
    <div style={{
      minHeight: "100vh",
      padding: "32px 24px 40px",
      display: "flex", flexDirection: "column",
      position: "relative",
    }}>
