        {!submitted ? (
          <form onSubmit={onSubmit}>
            <label style={{ display: "block", marginBottom: 8 }}>
              <span className="mono-xs" style={{ color: "var(--fg-faint)" }}>FREQUENCY / EMAIL</span>
