}

window.MobileView = MobileView;

// App root — responsive switcher + tweaks panel.

const { useTweaks, TweaksPanel, TweakSection, TweakRadio, TweakSlider, TweakToggle } = window;

const DEFAULTS = /*EDITMODE-BEGIN*/{
  "palette": "bio",
  "wheelStyle": "radial",
  "intensity": 1,
  "forceView": "auto",
  "breathing": true
}/*EDITMODE-END*/;

function useIsMobile() {
  const [m, setM] = useState(() => window.innerWidth < 820);
  useEffect(() => {
    const on = () => setM(window.innerWidth < 820);
    window.addEventListener("resize", on);
    return () => window.removeEventListener("resize", on);
  }, []);
  return m;
}

function App() {
  const [tweaks, setTweak] = useTweaks(DEFAULTS);
  const isMobile = useIsMobile();

  // Force override
  const forced = tweaks.forceView !== "auto" ? tweaks.forceView : (isMobile ? "mobile" : "desktop");

  // Apply palette to root
  useEffect(() => {
    document.documentElement.setAttribute("data-palette", tweaks.palette);
  }, [tweaks.palette]);

  // Update background intensity
  useEffect(() => {
    window.__bgIntensity = tweaks.intensity;
  }, [tweaks.intensity]);

  // Reveal-on-scroll observer
  useEffect(() => {
    const obs = new IntersectionObserver((entries) => {
      entries.forEach(e => { if (e.isIntersecting) e.target.classList.add("in"); });
    }, { threshold: 0.08 });
    document.querySelectorAll(".reveal").forEach(el => obs.observe(el));
    return () => obs.disconnect();
  }, [forced]);

  return (
    <>
      {forced === "mobile"
        ? <MobileView intensity={tweaks.intensity} />
        : <DesktopView intensity={tweaks.intensity} />
      }

      <TweaksPanel title="Tweaks">
        <TweakSection title="Palette">
          <TweakRadio
            value={tweaks.palette}
            onChange={(v) => setTweak("palette", v)}
            options={[
              { value: "bio",   label: "Bio Teal" },
              { value: "moss",  label: "Moss + Gold" },
              { value: "amber", label: "Amber Dusk" },
            ]}
          />
        </TweakSection>

        <TweakSection title="View">
          <TweakRadio
            value={tweaks.forceView}
            onChange={(v) => setTweak("forceView", v)}
            options={[
              { value: "auto",    label: "Auto (responsive)" },
              { value: "desktop", label: "Cockpit (desktop)" },
              { value: "mobile",  label: "Vestibule (mobile)" },
            ]}
          />
        </TweakSection>

        <TweakSection title="Atmosphere">
          <TweakSlider
            label="Intensity"
            value={tweaks.intensity}
            onChange={(v) => setTweak("intensity", v)}
            min={0} max={1.5} step={0.05}
          />
          <TweakToggle
            label="Breathing"
            value={tweaks.breathing}
            onChange={(v) => setTweak("breathing", v)}
          />
        </TweakSection>
      </TweaksPanel>
    </>
  );
}

ReactDOM.createRoot(document.getElementById("app")).render(<App />);

